// La solution moderne : async/await
async function chargerProfilUtilisateur(userId) {
  try {
    // await suspend l'exécution jusqu'à la résolution
    const response = await fetch(`/api/users/${userId}`);

    // Vérifier que la requête a réussi
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
    }

    const user = await response.json();
    const orders = await fetch(`/api/orders?userId=${userId}`);
    const ordersData = await orders.json();

    return { user, orders: ordersData };
  } catch (error) {
    console.error('Erreur de chargement:', error.message);
    return null;
  }
}

// Exécution en parallèle (plus performant quand les requêtes sont indépendantes)
async function chargerDashboard(userId) {
  const [user, orders, notifications] = await Promise.all([
    fetch(`/api/users/${userId}`).then(r => r.json()),
    fetch(`/api/orders?userId=${userId}`).then(r => r.json()),
    fetch(`/api/notifications?userId=${userId}`).then(r => r.json())
  ]);
  // Les 3 requêtes partent en même temps !
  return { user, orders, notifications };
}


