// Un programme Rust idiomatique : gestion d'erreurs propre
use std::collections::HashMap;

// Structure avec ownership automatique
#[derive(Debug, Clone)]
struct Etudiant {
    nom: String,
    scores: Vec<u32>,
}

impl Etudiant {
    fn new(nom: &str) -> Self {
        Etudiant {
            nom: nom.to_string(),
            scores: Vec::new(),
        }
    }

    fn ajouter_score(&mut self, score: u32) {
        self.scores.push(score);
    }

    fn moyenne(&self) -> Option<f64> {
        if self.scores.is_empty() {
            None  // Pas de panique, juste une valeur vide
        } else {
            let somme: u32 = self.scores.iter().sum();
            Some(somme as f64 / self.scores.len() as f64)
        }
    }
}

// Gestion d'erreurs avec Result<T, E>
#[derive(Debug)]
enum ErreurPromo {
    EtudiantInexistant(String),
    ScoreInvalide(u32),
}

struct Promotion {
    etudiants: HashMap<String, Etudiant>,
}

impl Promotion {
    fn ajouter_score(
        &mut self,
        nom: &str,
        score: u32,
    ) -> Result<(), ErreurPromo> {
        if score > 100 {
            return Err(ErreurPromo::ScoreInvalide(score));
        }
        self.etudiants
            .get_mut(nom)
            .ok_or_else(|| ErreurPromo::EtudiantInexistant(nom.to_string()))?
            .ajouter_score(score);
        Ok(())
    }
}

fn main() {
    let mut promo = Promotion {
        etudiants: HashMap::new(),
    };

    promo.etudiants.insert(
        "Alice".to_string(),
        Etudiant::new("Alice")
    );

    // Gestion d'erreur élégante avec match
    match promo.ajouter_score("Alice", 95) {
        Ok(()) => println!("Score ajouté !"),
        Err(e) => println!("Erreur : {:?}", e),
    }

    match promo.ajouter_score("Bob", 85) {
        Ok(()) => println!("Score ajouté !"),
        Err(ErreurPromo::EtudiantInexistant(nom)) => {
            println!("Étudiant '{}' introuvable", nom);
        }
        Err(e) => println!("Erreur : {:?}", e),
    }

    // Accès sécurisé avec pattern matching
    if let Some(alice) = promo.etudiants.get("Alice") {
        match alice.moyenne() {
            Some(moy) => println!("{} : {:.1}/100", alice.nom, moy),
            None => println!("Aucun score pour {}", alice.nom),
        }
    }
}
